#!/bin/bash\n\n# ============================================\n# AUTOMATED SETUP SCRIPT - RUN EVERYTHING\n# ============================================\n# This script automates the ENTIRE setup process\n# Just run: chmod +x setup.sh && ./setup.sh\n\nset -e\n\necho \"🚀 N8N REVENUE SYSTEM - COMPLETE AUTOMATED SETUP\"\necho \"=================================================\"\necho \"\"\n\n# Color codes\nGREEN='\\033[0;32m'\nBLUE='\\033[0;34m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m'\n\n# Step 1: Check prerequisites\necho \"${BLUE}STEP 1: Checking Prerequisites${NC}\"\necho \"-------------------------------------------\"\n\nif ! command -v docker &> /dev/null; then\n    echo \"❌ Docker not found. Install from: https://docker.com\"\n    exit 1\nfi\necho \"${GREEN}✅ Docker installed${NC}\"\n\nif ! command -v docker-compose &> /dev/null; then\n    echo \"❌ Docker Compose not found. Install from: https://docker.com/products/docker-compose\"\n    exit 1\nfi\necho \"${GREEN}✅ Docker Compose installed${NC}\"\n\nif ! command -v git &> /dev/null; then\n    echo \"❌ Git not found. Install from: https://git-scm.com\"\n    exit 1\nfi\necho \"${GREEN}✅ Git installed${NC}\"\n\necho \"\"\n\n# Step 2: Create necessary directories\necho \"${BLUE}STEP 2: Creating Directory Structure${NC}\"\necho \"-------------------------------------------\"\n\nmkdir -p workflows\nmkdir -p database\nmkdir -p config\nmkdir -p deployment\nmkdir -p scripts\nmkdir -p backups\nmkdir -p nginx/ssl\nmkdir -p nginx/conf.d\n\necho \"${GREEN}✅ Directories created${NC}\"\necho \"\"\n\n# Step 3: Check if .env exists, if not create it\necho \"${BLUE}STEP 3: Setting Up Environment Variables${NC}\"\necho \"-------------------------------------------\"\n\nif [ ! -f .env ]; then\n    echo \"Creating .env file...\"\n    cat > .env << 'EOF'\nDATABASE_URL=postgresql://revenue_admin:revenue_admin@postgres:5432/n8n_revenue\nPOSTGRES_USER=revenue_admin\nPOSTGRES_PASSWORD=revenue_admin\nPOSTGRES_DB=n8n_revenue\nN8N_HOST=0.0.0.0\nN8N_PORT=5678\nN8N_PROTOCOL=http\nN8N_EDITOR_BASE_URL=http://localhost:5678\nN8N_WEBHOOK_TUNNEL_URL=http://localhost:5678\nJWT_SECRET=$(openssl rand -base64 32)\nTIMEZONE=America/New_York\nEOF\n    echo \"${GREEN}✅ .env created${NC}\"\nelse\n    echo \"${GREEN}✅ .env already exists${NC}\"\nfi\necho \"\"\n\n# Step 4: Start Docker containers\necho \"${BLUE}STEP 4: Starting Docker Containers${NC}\"\necho \"-------------------------------------------\"\necho \"This may take 1-2 minutes on first run...\"\necho \"\"\n\ndocker-compose down 2>/dev/null || true\nsleep 2\ndocker-compose up -d\n\necho \"${GREEN}✅ Docker containers starting${NC}\"\necho \"\"\n\n# Step 5: Wait for services to be ready\necho \"${BLUE}STEP 5: Waiting for Services to Start${NC}\"\necho \"-------------------------------------------\"\n\necho \"Waiting for PostgreSQL...\"\nfor i in {1..30}; do\n    if docker exec n8n_revenue_db pg_isready -U revenue_admin 2>/dev/null | grep -q \"accepting\"; then\n        echo \"${GREEN}✅ PostgreSQL ready${NC}\"\n        break\n    fi\n    echo -n \".\"\n    sleep 2\ndone\n\necho \"\"\necho \"Waiting for N8N...\"\nfor i in {1..30}; do\n    if curl -s http://localhost:5678/api/v1/health | grep -q \"ok\"; then\n        echo \"${GREEN}✅ N8N ready${NC}\"\n        break\n    fi\n    echo -n \".\"\n    sleep 2\ndone\n\necho \"\"\necho \"\"\n\n# Step 6: Load sample data\necho \"${BLUE}STEP 6: Loading Sample Data${NC}\"\necho \"-------------------------------------------\"\n\nif [ -f database/seed-data.sql ]; then\n    docker exec -i n8n_revenue_db psql -U revenue_admin -d n8n_revenue < database/seed-data.sql 2>/dev/null || true\n    echo \"${GREEN}✅ Sample data loaded${NC}\"\n    \n    # Count loaded data\n    lead_count=$(docker exec n8n_revenue_db psql -U revenue_admin -d n8n_revenue -tc \"SELECT COUNT(*) FROM leads;\" 2>/dev/null | tr -d ' ')\n    echo \"   📊 Loaded $lead_count sample leads\"\nelse\n    echo \"${YELLOW}⚠️  seed-data.sql not found, skipping${NC}\"\nfi\necho \"\"\n\n# Step 7: Test the system\necho \"${BLUE}STEP 7: Testing System${NC}\"\necho \"-------------------------------------------\"\n\necho \"Testing N8N connection...\"\nif curl -s http://localhost:5678/api/v1/health | grep -q \"ok\"; then\n    echo \"${GREEN}✅ N8N is responding${NC}\"\nelse\n    echo \"${YELLOW}⚠️  N8N not responding yet, it may still be starting${NC}\"\nfi\n\necho \"Testing database connection...\"\nif docker exec n8n_revenue_db pg_isready -U revenue_admin 2>/dev/null | grep -q \"accepting\"; then\n    echo \"${GREEN}✅ PostgreSQL is responding${NC}\"\nelse\n    echo \"${YELLOW}⚠️  PostgreSQL not responding${NC}\"\nfi\n\necho \"Testing webhook endpoint...\"\nresponse=$(curl -s -o /dev/null -w \"%{http_code}\" http://localhost:5678/webhook/demo)\nif [ \"$response\" = \"200\" ] || [ \"$response\" = \"404\" ]; then\n    echo \"${GREEN}✅ Webhook endpoint accessible${NC}\"\nfi\n\necho \"\"\necho \"\"\n\n# Step 8: Create demo lead\necho \"${BLUE}STEP 8: Creating Test Lead${NC}\"\necho \"-------------------------------------------\"\n\necho \"Submitting test lead...\"\ntest_email=\"demo_$(date +%s)@example.com\"\ncurl -s -X POST http://localhost:5678/webhook/lead-capture \\\n  -H 'Content-Type: application/json' \\\n  -d \"{\n    \\\"name\\\": \\\"Demo User\\\",\n    \\\"email\\\": \\\"$test_email\\\",\n    \\\"phone\\\": \\\"555-0123\\\",\n    \\\"company\\\": \\\"Demo Company\\\",\n    \\\"company_size\\\": 100,\n    \\\"industry\\\": \\\"Technology\\\",\n    \\\"budget\\\": 75000,\n    \\\"timeline\\\": \\\"ASAP\\\",\n    \\\"source\\\": \\\"automated_setup\\\"\n  }\" > /dev/null 2>&1\n\necho \"${GREEN}✅ Test lead submitted${NC}\"\necho \"\"\n\n# Step 9: Display status\necho \"${BLUE}STEP 9: System Status${NC}\"\necho \"-------------------------------------------\"\n\necho \"Running containers:\"\ndocker-compose ps\n\necho \"\"\n\n# Step 10: Summary and next steps\necho \"\"\necho \"=================================================\"\necho \"${GREEN}🎉 SETUP COMPLETE!${NC}\"\necho \"=================================================\"\necho \"\"\n\necho \"${GREEN}✅ Your N8N Revenue System is Running!${NC}\"\necho \"\"\n\necho \"📍 ACCESS POINTS:\"\necho \"   N8N Editor:    ${BLUE}http://localhost:5678${NC}\"\necho \"   Database GUI:  ${BLUE}http://localhost:5050${NC}\"\necho \"   PostgreSQL:    ${BLUE}localhost:5432${NC}\"\necho \"\"\n\necho \"🔑 LOGIN CREDENTIALS:\"\necho \"   Database (PgAdmin):\"\necho \"     Email:    admin@example.com\"\necho \"     Password: admin\"\necho \"\"\necho \"   PostgreSQL:\"\necho \"     Username: revenue_admin\"\necho \"     Password: revenue_admin\"\necho \"\"\n\necho \"📚 DOCUMENTATION:\"\necho \"   Quick Start:       ${BLUE}QUICK_START.md${NC}\"\necho \"   Integration:       ${BLUE}INTEGRATION_GUIDE.md${NC}\"\necho \"   Full README:       ${BLUE}README.md${NC}\"\necho \"\"\n\necho \"🚀 NEXT STEPS:\"\necho \"\"\necho \"1. Open N8N Dashboard:\"\necho \"   ${BLUE}http://localhost:5678${NC}\"\necho \"\"\necho \"2. Import workflows from workflows/ folder\"\necho \"\"\necho \"3. Add your API credentials (HubSpot, SendGrid, etc.)\"\necho \"\"\necho \"4. Activate all workflows\"\necho \"\"\necho \"5. Follow INTEGRATION_GUIDE.md to connect lead sources\"\necho \"\"\necho \"6. Watch revenue grow automatically! 💰\"\necho \"\"\n\necho \"📧 TEST WEBHOOK:\"\necho \"   ${BLUE}curl -X POST http://localhost:5678/webhook/lead-capture -H 'Content-Type: application/json' -d '{\\\"name\\\":\\\"Test\\\",\\\"email\\\":\\\"test@example.com\\\",\\\"company\\\":\\\"Test Co\\\",\\\"budget\\\":50000,\\\"timeline\\\":\\\"ASAP\\\"}' ${NC}\"\necho \"\"\n\necho \"📊 VIEW DATA:\"\necho \"   docker exec -it n8n_revenue_db psql -U revenue_admin -d n8n_revenue\"\necho \"\"\n\necho \"🛑 STOP SYSTEM:\"\necho \"   docker-compose down\"\necho \"\"\n\necho \"=================================================\"\necho \"${GREEN}Ready to make money? Go to http://localhost:5678${NC}\"\necho \"=================================================\"\necho \"\"\n"
